// // This module selects between two 8-bit inputs based on a select signal.
// When sel is 1, output y should be equal to input a. When sel is 0, output y should be equal to input b.
module mux_2to1(
    input       [7:0]   a    ,   
    input       [7:0]   b    ,
    input               sel  ,

    output  reg [7:0]   y
);

    always @(*) begin
        case (sel)
            1'b0: y = a;
            1'b1: y = b;
            default: y = 8'd0;
        endcase
    end

endmodule
